async function seed() {
  if (!process.env.DATABASE_URL) {
    console.error("FATAL: DATABASE_URL is not set.");
    process.exit(1);
  }

  const client = new Client({ connectionString: process.env.DATABASE_URL });
  
  try {
    await client.connect();
    console.log("[Seed Hotspots] Connected to database. Seeding data...");
    
    // Ensure table structure exists first
    await client.query(`
      CREATE TABLE IF NOT EXISTS map_hotspots (
        shape_id     UUID PRIMARY KEY DEFAULT gen_random_uuid(),
        block_number INTEGER NOT NULL UNIQUE,
        points       JSONB NOT NULL,
        label        TEXT,
        created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
        updated_at   TIMESTAMPTZ NOT NULL DEFAULT NOW()
      );
    `);
    await client.query(`
      CREATE INDEX IF NOT EXISTS idx_map_hotspots_block ON map_hotspots (block_number);
    `);

    // Clean old hotspots to prevent duplicate block_number violations
    console.log("[Seed Hotspots] Cleaning old hotspots...");
    await client.query("DELETE FROM map_hotspots;");

    // Insert new hotspots
    let seeded = 0;
    for (const hs of hotspots) {
      await client.query(
        `INSERT INTO map_hotspots (shape_id, block_number, points, label)
         VALUES ($1, $2, $3::jsonb, $4)`,
        [hs.shape_id, hs.block_number, JSON.stringify(hs.points), hs.label]
      );
      seeded++;
    }
    
    console.log(`[Seed Hotspots] 🎉 Successfully seeded ${seeded} map hotspots!`);
  } catch (err) {
    console.error("[Seed Hotspots] ❌ Error:", err.message);
  } finally {
    await client.end();
  }
}

seed();
